import{_ as o,o as a,c as t,ag as d}from"./chunks/framework.CMYkYJvz.js";const h=JSON.parse('{"title":"Operation Reference","description":"Rule operation value formats and common usage.","frontmatter":{"title":"Operation Reference","description":"Rule operation value formats and common usage.","editLink":false},"headers":[],"relativePath":"en/reference/operations.md","filePath":"en/reference/operations.md"}'),c={name:"en/reference/operations.md"};function s(r,e,n,i,l,p){return a(),t("div",null,[...e[0]||(e[0]=[d('<blockquote><p>This page is automatically synced from <code>docs-en/operation.md</code>. Language: <strong>English</strong> | <a href="./../../reference/operations">中文</a></p></blockquote><h1 id="operation-reference" tabindex="-1">Operation Reference <a class="header-anchor" href="#operation-reference" aria-label="Permalink to &quot;Operation Reference&quot;">​</a></h1><p>Operations define what Bifrost does after a pattern matches. Values can be inline, parenthesized, referenced from an embedded value block defined in the same rule file, or referenced from a global Value created with <code>bifrost value add</code> (both forms resolve via <code>{key}</code> — verified on the real <code>bifrost start</code> path). Note that <code>file://</code>/<code>tpl://</code> treat their value as a file path, so to emit a value as content use a content op like <code>resBody://{key}</code>, not <code>file://{key}</code>.</p><h2 id="value-forms" tabindex="-1">Value Forms <a class="header-anchor" href="#value-forms" aria-label="Permalink to &quot;Value Forms&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pattern reqHeaders://X-Debug=1</span></span>\n<span class="line"><span>pattern resBody://(inline body with spaces)</span></span>\n<span class="line"><span>pattern resBody://{mock-response.json}    # {key} = an embedded block in this rule file or a global Value</span></span>\n<span class="line"><span>pattern urlParams://t=${now}&amp;id=${randomUUID}</span></span></code></pre></div><p>Template variables (<code>${...}</code>) expand unconditionally inside any value — backticks do not enable template parsing and are not special syntax (they pass through into the output literally). Backticks are only useful to protect a value that contains spaces from the rule-line tokenizer. Note: request-context vars (<code>${host}</code>, <code>${reqHeaders.x}</code>, …) work, but response-phase vars <code>${statusCode}</code> / <code>${resHeaders.x}</code> / <code>${resCookies.x}</code> and <code>${realHost}</code> / <code>${realPort}</code> / <code>${realUrl}</code> currently expand to an empty string (verified).</p><h2 id="categories" tabindex="-1">Categories <a class="header-anchor" href="#categories" aria-label="Permalink to &quot;Categories&quot;">​</a></h2><ul><li>Routing: <code>host</code>, <code>xhost</code>, <code>proxy</code>, <code>http</code>, <code>https</code>, <code>ws</code>, <code>wss</code>, <code>pac</code> (Proxy Auto-Config via inline scripts, embedded/global Values, local files, or remote URLs).</li><li>Request modification: <code>reqHeaders</code>, <code>reqCookies</code>, <code>urlParams</code>, <code>reqBody</code>, <code>method</code>, <code>auth</code>.</li><li>Response modification: <code>resHeaders</code>, <code>resCookies</code>, <code>statusCode</code>, <code>replaceStatus</code>, <code>resBody</code>, <code>file</code>, <code>tpl</code>.</li><li>Timing and throttling: <code>reqDelay</code>, <code>resDelay</code>, <code>reqSpeed</code>, <code>resSpeed</code>.</li><li>Scripts: <code>reqScript</code>, <code>resScript</code>, <code>decode</code>, <code>bp</code>.</li><li>TLS and upstream behavior: <code>tlsIntercept</code>, <code>tlsPassthrough</code>, <code>upstreamUnsafeSsl</code>.</li></ul><p>Use command-specific help and the detailed rule documents for exact value syntax.</p>',9)])])}const f=o(c,[["render",s]]);export{h as __pageData,f as default};
